namespace sv_1c1096b7f28149248ec2d90e7a0cca82.Models;

public class WizardData
{
    public HashSet<int> CompletedSteps { get; set; } = new();

    // Step 1: Personal Info
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = new();

    // Step 3: References
    public List<ReferenceEntry> References { get; set; } = new();
}

public class JobEntry
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public string Years { get; set; } = "";
}

public class ReferenceEntry
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string ContactInfo { get; set; } = "";
}

using System.Collections.Concurrent;
using sv_1c1096b7f28149248ec2d90e7a0cca82.Models;

namespace sv_1c1096b7f28149248ec2d90e7a0cca82.Services;

/// <summary>
/// Singleton service that stores wizard data server-side, keyed by session ID.
/// Accessible from both static SSR (layout) and interactive components (pages).
/// Each user session gets independent state via their unique session ID.
/// </summary>
public class WizardStateService : IDisposable
{
    private readonly ConcurrentDictionary<string, WizardEntry> _store = new();
    private readonly Timer _cleanupTimer;
    private static readonly TimeSpan EntryLifetime = TimeSpan.FromHours(2);
    private static readonly TimeSpan CleanupInterval = TimeSpan.FromMinutes(30);

    public WizardStateService()
    {
        _cleanupTimer = new Timer(_ => RemoveExpiredEntries(), null, CleanupInterval, CleanupInterval);
    }

    public WizardData GetOrCreate(string sessionId)
    {
        var entry = _store.GetOrAdd(sessionId, _ => new WizardEntry());
        entry.LastAccessed = DateTime.UtcNow;
        return entry.Data;
    }

    public void Save(string sessionId, WizardData data)
    {
        _store.AddOrUpdate(
            sessionId,
            _ => new WizardEntry { Data = data },
            (_, existing) =>
            {
                existing.Data = data;
                existing.LastAccessed = DateTime.UtcNow;
                return existing;
            });
    }

    private void RemoveExpiredEntries()
    {
        var cutoff = DateTime.UtcNow - EntryLifetime;
        foreach (var kvp in _store)
        {
            if (kvp.Value.LastAccessed < cutoff)
                _store.TryRemove(kvp.Key, out _);
        }
    }

    public void Dispose()
    {
        _cleanupTimer.Dispose();
    }

    private class WizardEntry
    {
        public WizardData Data { get; set; } = new();
        public DateTime LastAccessed { get; set; } = DateTime.UtcNow;
    }
}

