using Microsoft.AspNetCore.Components;
using sv_1c1096b7f28149248ec2d90e7a0cca82.Models;
using sv_1c1096b7f28149248ec2d90e7a0cca82.Services;

namespace sv_1c1096b7f28149248ec2d90e7a0cca82.Components.Pages.Apply;

/// <summary>
/// Base class for wizard step pages. Handles the session ID bridging
/// between static prerender (where HttpContext is available) and
/// the interactive circuit (where it is not).
/// </summary>
public abstract class WizardStepBase : ComponentBase, IDisposable
{
    [Inject] protected WizardStateService WizardService { get; set; } = default!;
    [Inject] protected NavigationManager Navigation { get; set; } = default!;
    [Inject] protected PersistentComponentState PersistentState { get; set; } = default!;
    [Inject] protected IHttpContextAccessor HttpContextAccessor { get; set; } = default!;

    protected WizardData Data { get; private set; } = new();
    protected abstract int StepNumber { get; }

    private string _sessionId = "";
    private PersistingComponentStateSubscription _subscription;

    protected override void OnInitialized()
    {
        // During prerender (static SSR), HttpContext is available.
        // During interactive circuit, it is not — restore from PersistentComponentState.
        if (HttpContextAccessor.HttpContext is { } ctx)
        {
            _sessionId = ctx.Session.Id;
            _subscription = PersistentState.RegisterOnPersisting(() =>
            {
                PersistentState.PersistAsJson("wizardSessionId", _sessionId);
                return Task.CompletedTask;
            });
        }
        else if (PersistentState.TryTakeFromJson<string>("wizardSessionId", out var restored))
        {
            _sessionId = restored!;
        }

        Data = WizardService.GetOrCreate(_sessionId);
    }

    protected void SaveAndNavigate(string url)
    {
        Data.CompletedSteps.Add(StepNumber);
        WizardService.Save(_sessionId, Data);
        Navigation.NavigateTo(url, forceLoad: true);
    }

    protected void SaveProgress()
    {
        WizardService.Save(_sessionId, Data);
    }

    protected void NavigateBack(string url)
    {
        WizardService.Save(_sessionId, Data);
        Navigation.NavigateTo(url, forceLoad: true);
    }

    public void Dispose()
    {
        _subscription.Dispose();
    }
}

