@page "/apply/personal-info"
@rendermode InteractiveServer
@inherits WizardStepBase
@using sv_1c1096b7f28149248ec2d90e7a0cca82.Models

<PageTitle>Apply - Personal Info</PageTitle>

<h3>Step 1: Personal Information</h3>

<EditForm Model="Data" OnValidSubmit="GoNext" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText @bind-Value="Data.FullName" class="form-control" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText @bind-Value="Data.Email" class="form-control" />
    </div>
    <div class="mb-3">
        <label class="form-label">Phone</label>
        <InputText @bind-Value="Data.Phone" class="form-control" />
    </div>
    <button type="submit" class="btn btn-primary">Next →</button>
</EditForm>

@code {
    protected override int StepNumber => 1;

    private void GoNext() => SaveAndNavigate("/apply/experience");
}

@page "/apply/experience"
@rendermode InteractiveServer
@inherits WizardStepBase
@using sv_1c1096b7f28149248ec2d90e7a0cca82.Models

<PageTitle>Apply - Experience</PageTitle>

<h3>Step 2: Work Experience</h3>

@foreach (var (job, index) in Data.JobHistory.Select((j, i) => (j, i)))
{
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input @bind="job.Company" class="form-control" />
        </div>
        <div class="mb-2">
            <label class="form-label">Job Title</label>
            <input @bind="job.Title" class="form-control" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input @bind="job.Years" class="form-control" />
        </div>
        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveJob(index)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="GoBack">← Back</button>
    <button class="btn btn-primary" @onclick="GoNext">Next →</button>
</div>

@code {
    protected override int StepNumber => 2;

    private void AddJob() => Data.JobHistory.Add(new JobEntry());
    private void RemoveJob(int index) => Data.JobHistory.RemoveAt(index);
    private void GoBack() => NavigateBack("/apply/personal-info");
    private void GoNext() => SaveAndNavigate("/apply/references");
}

@page "/apply/references"
@rendermode InteractiveServer
@inherits WizardStepBase
@using sv_1c1096b7f28149248ec2d90e7a0cca82.Models

<PageTitle>Apply - References</PageTitle>

<h3>Step 3: References</h3>

@foreach (var (reference, index) in Data.References.Select((r, i) => (r, i)))
{
    <div class="card mb-3 p-3">
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input @bind="reference.Name" class="form-control" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input @bind="reference.Relationship" class="form-control" />
        </div>
        <div class="mb-2">
            <label class="form-label">Contact Info</label>
            <input @bind="reference.ContactInfo" class="form-control" />
        </div>
        <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="GoBack">← Back</button>
    <button class="btn btn-primary" @onclick="GoNext">Next →</button>
</div>

@code {
    protected override int StepNumber => 3;

    private void AddReference() => Data.References.Add(new ReferenceEntry());
    private void RemoveReference(int index) => Data.References.RemoveAt(index);
    private void GoBack() => NavigateBack("/apply/experience");
    private void GoNext() => SaveAndNavigate("/apply/review");
}

@page "/apply/review"
@rendermode InteractiveServer
@inherits WizardStepBase
@using sv_1c1096b7f28149248ec2d90e7a0cca82.Models

<PageTitle>Apply - Review</PageTitle>

<h3>Step 4: Review Your Application</h3>

<div class="card mb-3 p-3">
    <h5>Personal Information</h5>
    <p><strong>Name:</strong> @Data.FullName</p>
    <p><strong>Email:</strong> @Data.Email</p>
    <p><strong>Phone:</strong> @Data.Phone</p>
</div>

<div class="card mb-3 p-3">
    <h5>Work Experience</h5>
    @if (Data.JobHistory.Count == 0)
    {
        <p class="text-muted">No experience entries added.</p>
    }
    @foreach (var job in Data.JobHistory)
    {
        <div class="mb-2">
            <strong>@job.Title</strong> at @job.Company (@job.Years)
        </div>
    }
</div>

<div class="card mb-3 p-3">
    <h5>References</h5>
    @if (Data.References.Count == 0)
    {
        <p class="text-muted">No references added.</p>
    }
    @foreach (var reference in Data.References)
    {
        <div class="mb-2">
            <strong>@reference.Name</strong> — @reference.Relationship (@reference.ContactInfo)
        </div>
    }
</div>

<div class="d-flex gap-2">
    <button class="btn btn-secondary" @onclick="GoBack">← Back</button>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@code {
    protected override int StepNumber => 4;

    private void GoBack() => NavigateBack("/apply/references");

    private void Submit()
    {
        Data.CompletedSteps.Add(StepNumber);
        SaveProgress();
        Navigation.NavigateTo("/", forceLoad: true);
    }
}

